1	// FCF margin trajectory chart — surfaces the "base case assumes today's clean
2	// FCF margin holds flat" assumption.
3	//
4	// X-axis: 3y history (oldest → newest) → TTM → Y1..Y5 flat at fcf_margin_ttm.
5	// Two thin lines (clean vs reported); SBC drag = shaded area between them.
6	
7	const WIDTH = 640;
8	const HEIGHT = 220;
9	const PAD_LEFT = 56;
10	const PAD_RIGHT = 56;
11	const PAD_TOP = 16;
12	const PAD_BOTTOM = 32;
13	
14	const CLEAN_COLOR = '#1565c0';
15	const REPORTED_COLOR = '#9c27b0';
16	const DRAG_FILL = 'rgba(156, 39, 176, 0.12)';
17	
18	const FALLBACK_NOTE = '3y history unavailable — re-run /stock-model with v1.11+ for trajectory.';
19	
20	function formatPct(value, digits = 1) {
21	  if (value == null || Number.isNaN(value)) return '—';
22	  return `${(value * 100).toFixed(digits)}%`;
23	}
24	
25	function shortYear(year) {
26	  if (!year) return '';
27	  // year format: "YYYY-MM-DD"
28	  return String(year).slice(0, 4);
29	}
30	
31	export default function FcfMarginTrajectory({ model }) {
32	  if (!model) return null;
33	  const method = typeof model.method === 'string' ? model.method : '';
34	  if (method.startsWith('pre-profit')) return null;
35	
36	  const cleanTtm = model.fcf_margin_ttm;
37	  const reportedTtm = model.fcf_margin_ttm_reported;
38	  if (cleanTtm == null && reportedTtm == null) return null;
39	
40	  const historical = Array.isArray(model.historical_fcf_margins)
41	    ? model.historical_fcf_margins
42	    : [];
43	
44	  // historical_fcf_margins[] is newest-first in the schema. Reverse so x-axis
45	  // moves past → future. Exclude the TTM-year row to avoid double-counting
46	  // (TTM is its own anchor between history and projection).
47	  const histAsc = [...historical].reverse();
48	  // Drop the newest historical entry if it duplicates TTM (same fiscal-year
49	  // value as fcf_margin_ttm). We compare by clean margin within epsilon.
50	  let histTrimmed = histAsc;
51	  if (histAsc.length > 0 && cleanTtm != null) {
52	    const last = histAsc[histAsc.length - 1];
53	    if (
54	      last.fcf_margin_clean != null &&
55	      Math.abs(last.fcf_margin_clean - cleanTtm) < 1e-6
56	    ) {
57	      histTrimmed = histAsc.slice(0, -1);
58	    }
59	  }
60	
61	  const hasHistory = histTrimmed.length > 0;
