file.content:
:root {
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
  color-scheme: light dark;
  color: #1a1a1a;
  background: #f7f7f7;
}

body {
  margin: 0;
  min-height: 100vh;
}

.app {
  max-width: 960px;
  margin: 0 auto;
  padding: 2rem 1.5rem;
}

.header {
  display: flex;
  align-items: baseline;
  gap: 1rem;
  margin-bottom: 1.5rem;
}

.header h1 {
  font-size: 1.5rem;
  margin: 0;
}

.header .date {
  color: #666;
  font-size: 0.9rem;
}

.tabs {
  display: flex;
  gap: 0.25rem;
  border-bottom: 1px solid #ddd;
  margin-bottom: 1.5rem;
}

.tab {
  padding: 0.5rem 1rem;
  background: none;
  border: none;
  border-bottom: 2px solid transparent;
  cursor: pointer;
  font-size: 0.95rem;
  color: #555;
}

.tab.active {
  border-bottom-color: #1a1a1a;
  color: #1a1a1a;
  font-weight: 600;
}

.tab:disabled {
  color: #bbb;
  cursor: default;
}

.badge {
  display: inline-block;
  padding: 0.25rem 0.75rem;
  border-radius: 999px;
  font-weight: 600;
  font-size: 0.85rem;
  letter-spacing: 0.05em;
  color: #fff;
}

.badge.pass { background: #2e7d32; }
.badge.watch { background: #ed8c00; }
.badge.skip { background: #c62828; }
.badge.unknown { background: #757575; }

.card {
  background: #fff;
  border: 1px solid #e5e5e5;
  border-radius: 8px;
  padding: 1.25rem 1.5rem;
}

.card h2 {
  margin: 0 0 1rem 0;
  display: flex;
  align-items: center;
  gap: 0.75rem;
  font-size: 1.1rem;
}

.rationale {
  margin-top: 1rem;
  color: #444;
  line-height: 1.5;
}

.ratios {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(140px, 1fr));
  gap: 0.75rem;
  margin-top: 1rem;
}

.ratio {
  background: #fafafa;
  border: 1px solid #eee;
  border-radius: 6px;
  padding: 0.5rem 0.75rem;
}

.ratio .label {
  color: #777;
  font-size: 0.75rem;
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

.ratio .value {
  font-size: 1.1rem;
  font-weight: 600;
  margin-top: 0.25rem;
}

.empty {
  color: #888;
  font-style: italic;
}

.picker {
  margin-left: auto;
  padding: 0.35rem 0.5rem;
  font-size: 0.9rem;
}

.model-header {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(160px, 1fr));
  gap: 0.75rem;
  margin-top: 1rem;
}

.model-header-cell {
  background: #fafafa;
  border: 1px solid #eee;
  border-radius: 6px;
  padding: 0.5rem 0.75rem;
}

.model-header-cell .label {
  color: #777;
  font-size: 0.75rem;
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

.model-header-cell .value {
  font-size: 0.95rem;
  font-weight: 600;
  margin-top: 0.25rem;
  word-break: break-word;
}

.iv-range {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 0.5rem;
  margin-top: 1.25rem;
}

.iv-cell {
  background: #fafafa;
  border: 1px solid #e5e5e5;
  border-radius: 6px;
  padding: 0.6rem 0.75rem;
  text-align: center;
}

.iv-cell .label {
  color: #777;
  font-size: 0.75rem;
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

.iv-cell .value {
  font-size: 1.15rem;
  font-weight: 600;
  margin-top: 0.25rem;
}

.iv-cell-current {
  border-color: #1a1a1a;
  background: #fff;
}

.iv-cell-current .label {
  color: #1a1a1a;
}

.position-sizing {
  margin-top: 1.25rem;
  padding-top: 1rem;
  border-top: 1px solid #eee;
}

.position-sizing-line {
  display: flex;
  align-items: center;
  gap: 0.75rem;
  flex-wrap: wrap;
}

.position-sizing-line .label {
  color: #777;
  font-size: 0.75rem;
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

.position-sizing-line .band {
  font-weight: 600;
  font-size: 1rem;
}

.pre-profit-note {
  margin-top: 1rem;
  font-size: 0.85rem;
}

.chart-block {
  margin-top: 1.5rem;
  padding-top: 1.25rem;
  border-top: 1px solid #eee;
}

.chart-title {
  font-size: 0.85rem;
  font-weight: 600;
  color: #444;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  margin-bottom: 0.5rem;
}

.chart-legend {
  display: flex;
  gap: 1rem;
  margin-bottom: 0.5rem;
  font-size: 0.8rem;
  color: #555;
}

.chart-legend .legend-item {
  display: inline-flex;
  align-items: center;
  gap: 0.35rem;
}

.chart-legend .legend-swatch {
  display: inline-block;
  width: 12px;
  height: 12px;
  border-radius: 2px;
}

.chart-legend .legend-diamond {
  width: 10px;
  height: 10px;
  background: #1565c0;
  border-radius: 0;
  transform: rotate(45deg);
}

.chart-svg {
  display: block;
  width: 100%;
  height: auto;
  max-width: 640px;
}

.chart-footnote {
  margin-top: 0.5rem;
  font-size: 0.8rem;
  color: #666;
  font-style: italic;
}

