// CAGR glidepath chart — trailing-3y CAGR → Y1..Y5 projected CAGR per scenario.
// Pure SVG, no chart dependency. Mounted from ModelReport only for ESTABLISHED
// runs (method does NOT start with "pre-profit").

const SCENARIOS = [
  { key: 'bear', label: 'Bear', color: '#c62828' },
  { key: 'base', label: 'Base', color: '#1565c0' },
  { key: 'bull', label: 'Bull', color: '#2e7d32' }
];

// X positions: trailing CAGR + Y1..Y5
const X_LABELS = ['trailing 3y', 'Y1', 'Y2', 'Y3', 'Y4', 'Y5'];

const WIDTH = 640;
const HEIGHT = 220;
const PAD_LEFT = 56;
const PAD_RIGHT = 72;
const PAD_TOP = 16;
const PAD_BOTTOM = 32;

function formatPct(value, digits = 1) {
  if (value == null || Number.isNaN(value)) return '—';
  return `${(value * 100).toFixed(digits)}%`;
}

function capFootnote(growthRate) {
  if (!growthRate || growthRate.cap_applied !== true) return null;
  const trailing = growthRate.trailing_3y_cagr;
  const applied = growthRate.applied_base_cagr;
  const source = growthRate.cap_source ?? 'unknown';
  // Canonical phrasing: "capped from <trailing>% by <source> (<applied>%)"
  return `Base-case Y2–Y5 CAGR capped from ${formatPct(trailing)} by ${source} (${formatPct(applied)}).`;
}

export default function CagrGlidepath({ model }) {
  if (!model) return null;
  const method = typeof model.method === 'string' ? model.method : '';
  if (method.startsWith('pre-profit')) return null;

  const fcfTtm = model.fcf_ttm;
  const fcfNormalized = model.fcf_normalized;
  const scenarios = model.scenarios ?? {};
  const growthRate = model.growth_rate ?? {};
  const trailing = growthRate.trailing_3y_cagr;
  const hasTrailing = trailing != null && Number.isFinite(trailing);

  // Y1 anchor: prefer fcf_normalized if positive (handles capex-distorted TTM like AMZN),
  // fall back to fcf_ttm if positive, else null → skip Y1 to avoid nonsensical growth rate.
  const y1Anchor =
    (fcfNormalized != null && Number.isFinite(fcfNormalized) && fcfNormalized > 0)
      ? fcfNormalized
      : (Number.isFinite(fcfTtm) && fcfTtm > 0)
        ? fcfTtm
        : null;

  // Build series: [trailing?, y1?, y2, y3, y4, y5] per scenario. Drop the
  // trailing column entirely when growth_rate.trailing_3y_cagr is missing
  // (older pre-v1.11 reports), so we never plot NaN. Drop Y1 when y1Anchor
  // is null (negative TTM and no normalised alternative).
  const series = SCENARIOS.map(({ key, label, color }) => {
    const s = scenarios[key];
    if (!s || !Number.isFinite(s.y1_fcf) || !Number.isFinite(s.y2_5_cagr)) {
      return null;
    }
    const y25Cagr = s.y2_5_cagr;
    if (y1Anchor !== null) {
      const y1Cagr = s.y1_fcf / y1Anchor - 1;
      const points = hasTrailing
        ? [trailing, y1Cagr, y25Cagr, y25Cagr, y25Cagr, y25Cagr]
        : [y1Cagr, y25Cagr, y25Cagr, y25Cagr, y25Cagr];
      return { key, label, color, points };
    }
    // Y1 anchor unavailable — skip Y1 point
    const points = hasTrailing
      ? [trailing, y25Cagr, y25Cagr, y25Cagr, y25Cagr]
      : [y25Cagr, y25Cagr, y25Cagr, y25Cagr];
    return { key, label, color, points };
  }).filter(Boolean);

  if (series.length === 0) return null;

  const baseLabels = hasTrailing ? X_LABELS : X_LABELS.slice(1);
  const xLabels = y1Anchor !== null ? baseLabels : baseLabels.filter((l) => l !== 'Y1');

  // Y-axis domain: include trailing + all scenario points, pad 10%
  const allValues = series.flatMap((s) => s.points).filter((v) => v != null && Number.isFinite(v));
  if (allValues.length === 0) return null;

  let yMin = Math.min(0, ...allValues);
  let yMax = Math.max(...allValues);
  if (yMin === yMax) yMax = yMin + 0.1;
  const yPad = (yMax - yMin) * 0.1;
  yMin -= yPad;
  yMax += yPad;

  const plotW = WIDTH - PAD_LEFT - PAD_RIGHT;
  const plotH = HEIGHT - PAD_TOP - PAD_BOTTOM;
  const xStep = xLabels.length > 1 ? plotW / (xLabels.length - 1) : 0;

  const xAt = (i) => PAD_LEFT + i * xStep;
  const yAt = (v) => PAD_TOP + plotH * (1 - (v - yMin) / (yMax - yMin));

  // Y-axis ticks: choose 4 ticks across the domain
  const tickCount = 4;
  const ticks = [];
  for (let i = 0; i <= tickCount; i += 1) {
    const v = yMin + ((yMax - yMin) * i) / tickCount;
    ticks.push(v);
  }

  // Zero baseline (when domain straddles 0)
  const zeroLine = yMin < 0 && yMax > 0 ? yAt(0) : null;

  const footnote = capFootnote(growthRate);

  return (
    <div className="chart-block">
      <div className="chart-title">CAGR glidepath</div>
      <div className="chart-legend">
        {SCENARIOS.map(({ key, label, color }) => (
          <span key={key} className="legend-item">
            <span className="legend-swatch" style={{ background: color }} />
            {label}
          </span>
        ))}
      </div>
      <svg
        className="chart-svg"
        viewBox={`0 0 ${WIDTH} ${HEIGHT}`}
        role="img"
        aria-label="CAGR glidepath chart"
      >
        {/* Y gridlines + tick labels */}
        {ticks.map((t, i) => (
          <g key={`tick-${i}`}>
            <line
              x1={PAD_LEFT}
              x2={WIDTH - PAD_RIGHT}
              y1={yAt(t)}
              y2={yAt(t)}
              stroke="#eee"
              strokeWidth="1"
            />
            <text
              x={PAD_LEFT - 8}
              y={yAt(t)}
              textAnchor="end"
              dominantBaseline="middle"
              fontSize="11"
              fill="#777"
            >
              {formatPct(t, 0)}
            </text>
          </g>
        ))}

        {/* Zero baseline */}
        {zeroLine != null && (
          <line
            x1={PAD_LEFT}
            x2={WIDTH - PAD_RIGHT}
            y1={zeroLine}
            y2={zeroLine}
            stroke="#bbb"
            strokeWidth="1"
            strokeDasharray="3 3"
          />
        )}

        {/* X-axis tick labels */}
        {xLabels.map((label, i) => (
          <text
            key={`xlbl-${i}`}
            x={xAt(i)}
            y={HEIGHT - PAD_BOTTOM + 16}
            textAnchor="middle"
            fontSize="11"
            fill="#777"
          >
            {label}
          </text>
        ))}

        {/* Series lines + point markers */}
        {series.map((s) => {
          const d = s.points
            .map((v, i) => `${i === 0 ? 'M' : 'L'}${xAt(i).toFixed(2)},${yAt(v).toFixed(2)}`)
            .join(' ');
          return (
            <g key={s.key}>
              <path d={d} fill="none" stroke={s.color} strokeWidth="2" />
              {s.points.map((v, i) => (
                <circle
                  key={`pt-${i}`}
                  cx={xAt(i)}
                  cy={yAt(v)}
                  r="3"
                  fill={s.color}
                />
              ))}
            </g>
          );
        })}

        {/* Y5 endpoint labels — collapse when all scenarios converge within 2pp */}
        {(() => {
          const CONVERGE_THRESHOLD = 0.02;
          const MIN_SEP = 14; // px
          const lastIdx = series[0].points.length - 1;
          const lx = xAt(lastIdx) + 8;
          const items = series.map((s) => ({
            key: s.key,
            color: s.color,
            value: s.points[lastIdx],
            rawY: yAt(s.points[lastIdx]),
          }));
          const vals = items.map((it) => it.value);
          const spread = Math.max(...vals) - Math.min(...vals);
          if (spread <= CONVERGE_THRESHOLD) {
            const avgY = items.reduce((sum, it) => sum + it.rawY, 0) / items.length;
            const avgVal = vals.reduce((a, b) => a + b, 0) / vals.length;
            return (
              <text
                x={lx}
                y={avgY}
                dominantBaseline="middle"
                fontSize="11"
                fill="#555"
                fontWeight="600"
              >
                {`all ≈ ${formatPct(avgVal)}`}
              </text>
            );
          }
          // Collision avoidance: sort by rawY, push apart by MIN_SEP
          const adj = [...items]
            .sort((a, b) => a.rawY - b.rawY)
            .map((it) => ({ ...it, adjY: it.rawY }));
          for (let i = 1; i < adj.length; i += 1) {
            if (adj[i].adjY - adj[i - 1].adjY < MIN_SEP) {
              adj[i].adjY = adj[i - 1].adjY + MIN_SEP;
            }
          }
          return adj.map((it) => (
            <g key={it.key}>
              {Math.abs(it.adjY - it.rawY) > 3 && (
                <line
                  x1={lx - 4}
                  y1={it.rawY}
                  x2={lx - 4}
                  y2={it.adjY}
                  stroke={it.color}
                  strokeWidth="0.7"
                  strokeOpacity="0.5"
                />
              )}
              <text
                x={lx}
                y={it.adjY}
                dominantBaseline="middle"
                fontSize="11"
                fill={it.color}
                fontWeight="600"
              >
                {formatPct(it.value)}
              </text>
            </g>
          ));
        })()}
      </svg>
      {footnote && <p className="chart-footnote">{footnote}</p>}
    </div>
  );
}

// FCF margin trajectory chart — surfaces the "base case assumes today's clean
// FCF margin holds flat" assumption.
//
// X-axis: 3y history (oldest → newest) → TTM → Y1..Y5 flat at fcf_margin_ttm.
// Two thin lines (clean vs reported); SBC drag = shaded area between them.

const WIDTH = 640;
const HEIGHT = 220;
const PAD_LEFT = 56;
const PAD_RIGHT = 56;
const PAD_TOP = 16;
const PAD_BOTTOM = 32;

const CLEAN_COLOR = '#1565c0';
const REPORTED_COLOR = '#9c27b0';
const DRAG_FILL = 'rgba(156, 39, 176, 0.12)';

const FALLBACK_NOTE = '3y history unavailable — re-run /stock-model with v1.11+ for trajectory.';

function formatPct(value, digits = 1) {
  if (value == null || Number.isNaN(value)) return '—';
  return `${(value * 100).toFixed(digits)}%`;
}

function shortYear(year) {
  if (!year) return '';
  // year format: "YYYY-MM-DD"
  return String(year).slice(0, 4);
}

export default function FcfMarginTrajectory({ model }) {
  if (!model) return null;
  const method = typeof model.method === 'string' ? model.method : '';
  if (method.startsWith('pre-profit')) return null;

  const cleanTtm = model.fcf_margin_ttm;
  const reportedTtm = model.fcf_margin_ttm_reported;
  if (cleanTtm == null && reportedTtm == null) return null;

  const historical = Array.isArray(model.historical_fcf_margins)
    ? model.historical_fcf_margins
    : [];

  // historical_fcf_margins[] is newest-first in the schema. Reverse so x-axis
  // moves past → future. Exclude the TTM-year row to avoid double-counting
  // (TTM is its own anchor between history and projection).
  const histAsc = [...historical].reverse();
  // Drop the newest historical entry if it duplicates TTM (same fiscal-year
  // value as fcf_margin_ttm). We compare by clean margin within epsilon.
  let histTrimmed = histAsc;
  if (histAsc.length > 0 && cleanTtm != null) {
    const last = histAsc[histAsc.length - 1];
    if (
      last.fcf_margin_clean != null &&
      Math.abs(last.fcf_margin_clean - cleanTtm) < 1e-6
    ) {
      histTrimmed = histAsc.slice(0, -1);
    }
  }

  const hasHistory = histTrimmed.length > 0;

  // Build the canonical x-axis labels and a points array per series.
  // Columns: [hist...n], 'TTM', 'Y1', 'Y2', 'Y3', 'Y4', 'Y5'
  const histLabels = histTrimmed.map((h) => shortYear(h.year));
  const projLabels = ['TTM', 'Y1', 'Y2', 'Y3', 'Y4', 'Y5'];
  const xLabels = [...histLabels, ...projLabels];

  const cleanPoints = [
    ...histTrimmed.map((h) =>
      h.fcf_margin_clean != null ? h.fcf_margin_clean : null
    ),
    cleanTtm ?? null,
    cleanTtm ?? null,
    cleanTtm ?? null,
    cleanTtm ?? null,
    cleanTtm ?? null,
    cleanTtm ?? null
  ];
  const reportedPoints = [
    ...histTrimmed.map((h) =>
      h.fcf_margin_reported != null ? h.fcf_margin_reported : null
    ),
    reportedTtm ?? null,
    reportedTtm ?? null,
    reportedTtm ?? null,
    reportedTtm ?? null,
    reportedTtm ?? null,
    reportedTtm ?? null
  ];

  const allValues = [...cleanPoints, ...reportedPoints].filter(
    (v) => v != null && Number.isFinite(v)
  );
  if (allValues.length === 0) return null;

  let yMin = Math.min(0, ...allValues);
  let yMax = Math.max(...allValues);
  if (yMin === yMax) yMax = yMin + 0.1;
  const yPad = (yMax - yMin) * 0.1;
  yMin -= yPad;
  yMax += yPad;

  const plotW = WIDTH - PAD_LEFT - PAD_RIGHT;
  const plotH = HEIGHT - PAD_TOP - PAD_BOTTOM;
  const colCount = xLabels.length;
  const xStep = colCount > 1 ? plotW / (colCount - 1) : 0;

  const xAt = (i) => PAD_LEFT + i * xStep;
  const yAt = (v) => PAD_TOP + plotH * (1 - (v - yMin) / (yMax - yMin));

  const tickCount = 4;
  const ticks = [];
  for (let i = 0; i <= tickCount; i += 1) {
    ticks.push(yMin + ((yMax - yMin) * i) / tickCount);
  }
  const zeroLine = yMin < 0 && yMax > 0 ? yAt(0) : null;

  // Build the SBC-drag polygon: across columns where both clean and reported
  // are present, walk forward on reported (upper), then backward on clean.
  const dragIndices = [];
  for (let i = 0; i < colCount; i += 1) {
    if (
      cleanPoints[i] != null &&
      reportedPoints[i] != null &&
      Number.isFinite(cleanPoints[i]) &&
      Number.isFinite(reportedPoints[i])
    ) {
      dragIndices.push(i);
    }
  }
  let dragPath = '';
  if (dragIndices.length >= 2) {
    const upper = dragIndices
      .map((i, idx) =>
        `${idx === 0 ? 'M' : 'L'}${xAt(i).toFixed(2)},${yAt(reportedPoints[i]).toFixed(2)}`
      )
      .join(' ');
    const lower = [...dragIndices]
      .reverse()
      .map((i) => `L${xAt(i).toFixed(2)},${yAt(cleanPoints[i]).toFixed(2)}`)
      .join(' ');
    dragPath = `${upper} ${lower} Z`;
  }

  const buildLinePath = (points) => {
    const segments = [];
    let started = false;
    for (let i = 0; i < points.length; i += 1) {
      const v = points[i];
      if (v == null || !Number.isFinite(v)) {
        started = false;
        continue;
      }
      segments.push(`${started ? 'L' : 'M'}${xAt(i).toFixed(2)},${yAt(v).toFixed(2)}`);
      started = true;
    }
    return segments.join(' ');
  };

  const cleanPath = buildLinePath(cleanPoints);
  const reportedPath = buildLinePath(reportedPoints);

  // Vertical divider between history+TTM and projection (Y1..Y5).
  // Position: between TTM column and Y1 column.
  const ttmIdx = histLabels.length; // index of 'TTM'
  const dividerX = ttmIdx + 1 < colCount ? (xAt(ttmIdx) + xAt(ttmIdx + 1)) / 2 : null;

  return (
    <div className="chart-block">
      <div className="chart-title">FCF margin trajectory</div>
      <div className="chart-legend">
        <span className="legend-item">
          <span className="legend-swatch" style={{ background: CLEAN_COLOR }} />
          Clean (SBC-stripped)
        </span>
        <span className="legend-item">
          <span className="legend-swatch" style={{ background: REPORTED_COLOR }} />
          Reported
        </span>
        <span className="legend-item">
          <span
            className="legend-swatch"
            style={{ background: DRAG_FILL, border: '1px solid #d1c4e9' }}
          />
          SBC drag
        </span>
      </div>
      <svg
        className="chart-svg"
        viewBox={`0 0 ${WIDTH} ${HEIGHT}`}
        role="img"
        aria-label="FCF margin trajectory chart"
      >
        {ticks.map((t, i) => (
          <g key={`tick-${i}`}>
            <line
              x1={PAD_LEFT}
              x2={WIDTH - PAD_RIGHT}
              y1={yAt(t)}
              y2={yAt(t)}
              stroke="#eee"
              strokeWidth="1"
            />
            <text
              x={PAD_LEFT - 8}
              y={yAt(t)}
              textAnchor="end"
              dominantBaseline="middle"
              fontSize="11"
              fill="#777"
            >
              {formatPct(t, 0)}
            </text>
          </g>
        ))}

        {zeroLine != null && (
          <line
            x1={PAD_LEFT}
            x2={WIDTH - PAD_RIGHT}
            y1={zeroLine}
            y2={zeroLine}
            stroke="#bbb"
            strokeWidth="1"
            strokeDasharray="3 3"
          />
        )}

        {dividerX != null && (
          <line
            x1={dividerX}
            x2={dividerX}
            y1={PAD_TOP}
            y2={HEIGHT - PAD_BOTTOM}
            stroke="#bbb"
            strokeWidth="1"
            strokeDasharray="2 4"
          />
        )}

        {xLabels.map((label, i) => (
          <text
            key={`xlbl-${i}`}
            x={xAt(i)}
            y={HEIGHT - PAD_BOTTOM + 16}
            textAnchor="middle"
            fontSize="11"
            fill="#777"
          >
            {label}
          </text>
        ))}

        {/* SBC drag shaded area */}
        {dragPath && <path d={dragPath} fill={DRAG_FILL} stroke="none" />}

        {/* Reported line */}
        {reportedPath && (
          <path d={reportedPath} fill="none" stroke={REPORTED_COLOR} strokeWidth="2" />
        )}
        {reportedPoints.map((v, i) =>
          v != null && Number.isFinite(v) ? (
            <circle
              key={`rep-${i}`}
              cx={xAt(i)}
              cy={yAt(v)}
              r="2.5"
              fill={REPORTED_COLOR}
            />
          ) : null
        )}

        {/* Clean line */}
        {cleanPath && (
          <path d={cleanPath} fill="none" stroke={CLEAN_COLOR} strokeWidth="2" />
        )}
        {cleanPoints.map((v, i) =>
          v != null && Number.isFinite(v) ? (
            <circle
              key={`cln-${i}`}
              cx={xAt(i)}
              cy={yAt(v)}
              r="2.5"
              fill={CLEAN_COLOR}
            />
          ) : null
        )}
      </svg>
      {!hasHistory && <p className="chart-footnote">{FALLBACK_NOTE}</p>}
    </div>
  );
}

// Scenario fan chart — Y1..Y5 FCF/share per bear/base/bull, with per-share
// terminal IV diamond markers and a horizontal current-price reference line.
// Single per-share axis across the whole chart.

const SCENARIOS = [
  { key: 'bear', label: 'Bear', color: '#c62828' },
  { key: 'base', label: 'Base', color: '#1565c0' },
  { key: 'bull', label: 'Bull', color: '#2e7d32' }
];

const Y_LABELS = ['Y1', 'Y2', 'Y3', 'Y4', 'Y5'];

const WIDTH = 640;
const HEIGHT = 260;
const PAD_LEFT = 64;
const PAD_RIGHT = 80;
const PAD_TOP = 16;
const PAD_BOTTOM = 32;

const CURRENT_COLOR = '#1a1a1a';

function formatDollar(value, digits = 2) {
  if (value == null || !Number.isFinite(value)) return '—';
  const n = Number(value);
  if (Math.abs(n) >= 1000) return `$${n.toFixed(0)}`;
  return `$${n.toFixed(digits)}`;
}

export default function ScenarioFan({ model }) {
  if (!model) return null;
  const method = typeof model.method === 'string' ? model.method : '';
  if (method.startsWith('pre-profit')) return null;

  const shares = model.shares_diluted;
  const currentPrice = model.current_price;
  const scenarios = model.scenarios ?? {};
  if (
    shares == null ||
    !Number.isFinite(shares) ||
    shares <= 0
  ) {
    return null;
  }

  // Build per-share FCF series for each scenario.
  const series = SCENARIOS.map(({ key, label, color }) => {
    const s = scenarios[key];
    if (!s || !Number.isFinite(s.y1_fcf) || !Number.isFinite(s.y2_5_cagr)) {
      return null;
    }
    const y1ps = s.y1_fcf / shares;
    const points = [y1ps];
    let running = y1ps;
    for (let i = 0; i < 4; i += 1) {
      running *= 1 + s.y2_5_cagr;
      points.push(running);
    }
    return {
      key,
      label,
      color,
      points,
      iv: Number.isFinite(s.intrinsic_value_per_share)
        ? s.intrinsic_value_per_share
        : null
    };
  }).filter(Boolean);

  if (series.length === 0) return null;

  // Collect all values that need to fit on the axis.
  const fanValues = series.flatMap((s) => s.points);
  const ivValues = series.map((s) => s.iv).filter((v) => v != null);
  const refValues = Number.isFinite(currentPrice) ? [currentPrice] : [];
  const allValues = [...fanValues, ...ivValues, ...refValues];
  if (allValues.length === 0) return null;

  let yMin = Math.min(0, ...allValues);
  let yMax = Math.max(...allValues);
  if (yMin === yMax) yMax = yMin + 1;
  const yPad = (yMax - yMin) * 0.08;
  yMin -= yPad;
  yMax += yPad;

  const plotW = WIDTH - PAD_LEFT - PAD_RIGHT;
  const plotH = HEIGHT - PAD_TOP - PAD_BOTTOM;
  const xStep = plotW / (Y_LABELS.length - 1);

  const xAt = (i) => PAD_LEFT + i * xStep;
  const yAt = (v) => PAD_TOP + plotH * (1 - (v - yMin) / (yMax - yMin));

  const tickCount = 5;
  const ticks = [];
  for (let i = 0; i <= tickCount; i += 1) {
    ticks.push(yMin + ((yMax - yMin) * i) / tickCount);
  }

  // Current-price line position
  const currentY = Number.isFinite(currentPrice) ? yAt(currentPrice) : null;

  // Diamond size
  const DIAMOND = 6;

  return (
    <div className="chart-block">
      <div className="chart-title">Scenario fan (per share)</div>
      <div className="chart-legend">
        {SCENARIOS.map(({ key, label, color }) => (
          <span key={key} className="legend-item">
            <span className="legend-swatch" style={{ background: color }} />
            {label}
          </span>
        ))}
        <span className="legend-item">
          <span
            className="legend-swatch"
            style={{ background: CURRENT_COLOR, height: '2px', marginTop: '5px' }}
          />
          Current price
        </span>
        <span className="legend-item">
          <span className="legend-swatch legend-diamond" />
          Terminal IV
        </span>
      </div>
      <svg
        className="chart-svg"
        viewBox={`0 0 ${WIDTH} ${HEIGHT}`}
        role="img"
        aria-label="Scenario fan chart"
      >
        {ticks.map((t, i) => (
          <g key={`tick-${i}`}>
            <line
              x1={PAD_LEFT}
              x2={WIDTH - PAD_RIGHT}
              y1={yAt(t)}
              y2={yAt(t)}
              stroke="#eee"
              strokeWidth="1"
            />
            <text
              x={PAD_LEFT - 8}
              y={yAt(t)}
              textAnchor="end"
              dominantBaseline="middle"
              fontSize="11"
              fill="#777"
            >
              {formatDollar(t, 0)}
            </text>
          </g>
        ))}

        {Y_LABELS.map((label, i) => (
          <text
            key={`xlbl-${i}`}
            x={xAt(i)}
            y={HEIGHT - PAD_BOTTOM + 16}
            textAnchor="middle"
            fontSize="11"
            fill="#777"
          >
            {label}
          </text>
        ))}

        {/* Current-price reference line */}
        {currentY != null && (
          <g>
            <line
              x1={PAD_LEFT}
              x2={WIDTH - PAD_RIGHT}
              y1={currentY}
              y2={currentY}
              stroke={CURRENT_COLOR}
              strokeWidth="1.5"
              strokeDasharray="6 4"
            />
            <text
              x={WIDTH - PAD_RIGHT + 6}
              y={currentY}
              dominantBaseline="middle"
              fontSize="11"
              fontWeight="600"
              fill={CURRENT_COLOR}
            >
              {formatDollar(currentPrice)}
            </text>
          </g>
        )}

        {/* Fan lines */}
        {series.map((s) => {
          const d = s.points
            .map((v, i) => `${i === 0 ? 'M' : 'L'}${xAt(i).toFixed(2)},${yAt(v).toFixed(2)}`)
            .join(' ');
          return (
            <g key={`fan-${s.key}`}>
              <path d={d} fill="none" stroke={s.color} strokeWidth="2" />
              {s.points.map((v, i) => (
                <circle
                  key={`fpt-${s.key}-${i}`}
                  cx={xAt(i)}
                  cy={yAt(v)}
                  r="2.5"
                  fill={s.color}
                />
              ))}
            </g>
          );
        })}

        {/* Terminal IV diamond markers + value labels at Y5 */}
        {series.map((s) => {
          if (s.iv == null) return null;
          const cx = xAt(Y_LABELS.length - 1);
          const cy = yAt(s.iv);
          const diamond = `${cx},${cy - DIAMOND} ${cx + DIAMOND},${cy} ${cx},${cy + DIAMOND} ${cx - DIAMOND},${cy}`;
          return (
            <g key={`iv-${s.key}`}>
              <polygon
                points={diamond}
                fill={s.color}
                stroke="#fff"
                strokeWidth="1.5"
              />
              <text
                x={cx + DIAMOND + 6}
                y={cy}
                dominantBaseline="middle"
                fontSize="11"
                fontWeight="600"
                fill={s.color}
              >
                {formatDollar(s.iv)}
              </text>
            </g>
          );
        })}
      </svg>
    </div>
  );
}

